```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using arithmetic deserialization
    adaptor >> packet.packet_id;

    // Read username using prefixed adaptor
    adaptor >> hexi::prefixed(packet.username);

    // Read score count and then use read_container to read scores vector
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.read_container(packet.scores, score_count);

    // Read metadata using null_terminated adaptor
    adaptor >> hexi::null_terminated(packet.metadata);

    // Calculate padding and skip remaining bytes
    // Total bytes read so far: sizeof(packet_id) + username length + 4 (score count) + scores size + metadata length
    size_t total_read = sizeof(packet.packet_id) + packet.username.size() + 4 + (packet.scores.size() * sizeof(uint32_t)) + packet.metadata.size();
    size_t padding = buffer.size() - total_read;
    if (padding > 0) {
        adaptor.skip(padding);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    PacketInfo info;

    // Use span() to get packet_id (first 4 bytes)
    info.packet_id = *reinterpret_cast<const uint32_t*>(buffer.data());

    // Use prefixed adaptor to read username (string_view with length prefix)
    adaptor.skip(sizeof(uint32_t)); // Skip the length prefix we already accessed
    adaptor >> hexi::prefixed(info.username);

    // Read score count and skip scores data
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

**Explanation:**

1. **deserialize_packet function:**
   - Creates a `buffer_adaptor` from the input buffer
   - Uses `operator>>` to deserialize `packet_id` as arithmetic type
   - Uses `prefixed` adaptor to read username with length prefix
   - Reads score count first, then uses `read_container` to populate scores vector
   - Uses `null_terminated` adaptor to read metadata string
   - Calculates padding by comparing total bytes read vs buffer size and skips remaining bytes

2. **extract_packet_info function:**
   - Uses `span()` to directly access packet_id (first 4 bytes) without creating an adaptor
   - Uses `prefixed` adaptor to read username as string_view
   - Reads score count and skips the entire scores data section
   - Returns only the required partial information

Both functions properly utilize the Hexi library's streaming interface and adaptors as specified in the assessment objectives.

