    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input span
    // Note: We need to work with non-const buffer for buffer_adaptor
    std::span<uint8_t> non_const_buffer = const_cast<std::span<uint8_t>>(buffer);
    hexi::buffer_adaptor adaptor(non_const_buffer);

    DataResult result;

    // Use buffer_adaptor's copy method to preview the first byte (data_type)
    adaptor.copy(&result.data_type, 1);

    // Calculate total required bytes: 1 (data_type) + 4 (item_count) + (item_count * sizeof(item_type))
    uint32_t item_count;
    adaptor.copy(&item_count, sizeof(item_count));

    const size_t total_required_bytes = 1 + sizeof(item_count) + 
                                       (result.data_type == 0 ? item_count * sizeof(uint32_t) : item_count * sizeof(float));

    // Check if buffer has enough data using buffer_adaptor's size method
    if (adaptor.size() < total_required_bytes) {
        throw std::runtime_error("Insufficient data in buffer");
    }

    // Reset the adaptor's read position to start reading from beginning
    // Create a new adaptor to reset position
    hexi::buffer_adaptor read_adaptor(non_const_buffer);

    // Read item_count using binary_stream
    hexi::binary_stream stream(read_adaptor);
    stream >> item_count;

    // Based on data_type, read appropriate items using binary_stream
    if (result.data_type == 0) {
        // Read uint32_t items
        std::vector<uint32_t> items(item_count);
        for (auto& item : items) {
            stream >> item;
