bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer_adaptor for the provided buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Check available space using buffer_adaptor's free() function
    auto available_space = adaptor.free();

    // Calculate total required space: sizeof(header) + items.size() * sizeof(uint32_t)
    auto required_space = sizeof(header) + items.size() * sizeof(uint32_t);

    // If insufficient space, return false
    if (available_space < required_space) {
        return false;
    }

    // Get the write pointer from buffer_adaptor using write_ptr()
    auto* write_ptr = adaptor.write_ptr();

    // Write the header to the write pointer location
    std::memcpy(write_ptr, &header, sizeof(header));

    // Advance write pointer after header
    write_ptr += sizeof(header);

    // Write container data using write_container
    // Create binary_stream for writing container data
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Write items using write_container
    stream.write_container(items);

    // Return true if all writes were successful
    return true;
}
