```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Write the entire vector data to the buffer
    buffer.write(data.data(), data.size());
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    // Check if the buffer has enough data to read the specified number of bytes
    if (buffer.size() < bytes_to_read) {
        // Return empty vector if not enough data is available
        return {};
    }

    // Create a destination vector with the required size
    std::vector<uint8_t> destination(bytes_to_read);

    // Use the read method of the static_buffer to read the specified number of bytes
    buffer.read(destination.data(), bytes_to_read);

    // Convert the read data to a vector and return it
    return destination;
}
```

## Key Implementation Points:

1. **Write Function** (`write_data_to_buffer`):
   - Uses `buffer.write()` method with `data.data()` (pointer to vector data) and `data.size()` (number of bytes)
